import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";

export default function Profile() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working"); // working, free
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  const [workerInfo, setWorkerInfo] = useState({
    name: "Jenna Stones",
    role: "Développeuse Full Stack",
    experience: "5 ans d'expérience",
    skills: ["React.js", "Node.js", "Tailwind CSS", "Figma"],
    bio: "Développeuse passionnée avec une expertise en création d'applications web modernes. J'aime relever des défis techniques et créer des expériences utilisateur exceptionnelles.",
    email: "jenna@example.com",
    phone: "+33 6 12 34 56 78"
  });
  
  const [workHistory, setWorkHistory] = useState([
    { place: "Le Café Paris", role: "Développeuse Frontend", duration: "2023 - Présent", rating: 5, review: "Excellente développeuse, très professionnelle" },
    { place: "Tech Startup Lyon", role: "Développeuse Web", duration: "2021 - 2023", rating: 4, review: "Bon travail, équipe sympathique" },
    { place: "Agence Digital", role: "Stagiaire Développeuse", duration: "2020 - 2021", rating: 4.5, review: "Apprentissage rapide, très motivée" }
  ]);
  
  const [currentRating, setCurrentRating] = useState(0);
  const [currentReview, setCurrentReview] = useState("");
  const [managerComment, setManagerComment] = useState("");
  
  // أماكن العمل المتاحة
  const availablePlaces = [
    { id: 1, name: "Le Café Paris", location: "Paris", type: "Café" },
    { id: 2, name: "Restaurant La Mer", location: "Marseille", type: "Restaurant" },
    { id: 3, name: "Tech Hub Lyon", location: "Lyon", type: "Bureau" },
    { id: 4, name: "Startup Factory", location: "Toulouse", type: "Coworking" }
  ];
  
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [showPlaceSelector, setShowPlaceSelector] = useState(false);
  
  // دالة لإضافة تقييم من المدير
  const addManagerReview = () => {
    if (currentRating > 0 && managerComment) {
      const newHistory = {
        place: currentWorkPlace,
        role: workerInfo.role,
        duration: "Nouvelle période",
        rating: currentRating,
        review: managerComment
      };
      setWorkHistory([newHistory, ...workHistory]);
      setCurrentRating(0);
      setManagerComment("");
      alert("✅ تم إضافة التقييم بنجاح!");
    } else {
      alert("⚠️ الرجاء إدخال التقييم والتعليق");
    }
  };
  
  // دالة لتغيير مكان العمل
  const changeWorkPlace = (place) => {
    setCurrentWorkPlace(place.name);
    setSelectedPlace(place);
    setShowPlaceSelector(false);
    setWorkerStatus("working");
    alert(`✅ تم تغيير مكان العمل إلى: ${place.name}`);
  };
  
  // دالة لتعطيل العامل (خروجه من العمل)
  const deactivateWorker = () => {
    setWorkerStatus("free");
    setCurrentWorkPlace("");
    alert("⚠️ تم تغيير حالة العامل إلى: عاطل عن العمل");
  };
  
  // دالة لتفعيل العامل
  const activateWorker = () => {
    setShowPlaceSelector(true);
  };
  
  const morphingStyle = `
    .morphing-bg {
      width: 100%;
      max-width: 1100px;
      min-height: 420px;
      background: linear-gradient(45deg, #ee7752, #e73c7e, #23a6d5, #23d5ad);
      background-size: 400% 400%;
      animation: gradient 8s ease infinite, morph 8s ease-in-out infinite;
      border-radius: 30px;
      transform-style: preserve-3d;
      box-shadow: 0 20px 40px rgba(0,0,0,0.3);
      border: 2px solid rgba(255,255,255,0.2);
      margin: 0 auto;
      padding: 90px 20px 30px 20px;
      position: relative;
      margin-top: 90px;
    }
    
    @keyframes gradient {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes morph {
      0% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
      50% { border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%; }
      100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
    }
    
    .image-wrapper {
      position: absolute;
      top: -90px;
      left: 50%;
      transform: translateX(-50%);
      z-index: 20;
    }
    
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
    }
    
    .cards-container {
      display: flex;
      gap: 30px;
      justify-content: center;
      margin-top: 30px;
      flex-wrap: wrap;
    }
    
    .cv-card {
      flex: 1;
      min-width: 280px;
      background: rgba(255,255,255,0.15);
      backdrop-filter: blur(15px);
      border-radius: 25px;
      padding: 25px;
      cursor: pointer;
      transition: all 0.3s ease;
      border: 1px solid rgba(255,255,255,0.3);
      text-align: center;
    }
    
    .cv-card:hover {
      transform: translateY(-10px);
      background: rgba(255,255,255,0.25);
      border-color: #22c55e;
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.85);
      z-index: 100;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 600px;
      width: 90%;
      max-height: 80vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      box-shadow: 0 0 40px rgba(34,197,94,0.3);
    }
    
    .stars {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin: 15px 0;
    }
    
    .star-btn {
      font-size: 30px;
      background: none;
      border: none;
      cursor: pointer;
      color: #ffc107;
      transition: transform 0.2s;
    }
    
    .star-btn:hover {
      transform: scale(1.2);
    }
    
    .work-history-item {
      background: rgba(255,255,255,0.1);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
    }
    
    .status-working {
      background: #22c55e;
      color: white;
    }
    
    .status-free {
      background: #ef4444;
      color: white;
    }
    
    .place-selector {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 15px;
      margin-top: 20px;
    }
    
    .place-option {
      background: rgba(34,197,94,0.2);
      border: 1px solid #22c55e;
      border-radius: 15px;
      padding: 15px;
      cursor: pointer;
      transition: all 0.3s;
      text-align: center;
    }
    
    .place-option:hover {
      background: rgba(34,197,94,0.4);
      transform: scale(1.02);
    }
    
    .rating-input {
      display: flex;
      gap: 8px;
      justify-content: center;
      margin: 10px 0;
    }
    
    .rating-star {
      font-size: 28px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star.active {
      color: #ffc107;
    }
    
    @media (max-width: 768px) {
      .morphing-bg {
        min-height: 500px;
        border-radius: 20px;
        padding: 75px 15px 25px 15px;
        margin-top: 75px;
      }
      .image-wrapper {
        top: -75px;
      }
      .cards-container {
        flex-direction: column;
      }
    }
  `;

  return (
    <>
      <style>{morphingStyle}</style>
      
      <div className="profile-hero-section" style={{ position: 'relative', minHeight: '100vh' }}>
        
        <div className="shooting-stars">
          {[...Array(50)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(8)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "400px" }}>
            <div className="absolute top-0 w-full h-full bg-center bg-cover"
              style={{ backgroundImage: "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')" }}>
            </div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="relative">
                        <img alt="..." src={require("assets/img/team-2-800x800.jpg").default}
                          className="shadow-xl rounded-full h-auto align-middle border-none absolute -m-16 -ml-20 lg:-ml-16 max-w-150-px" />
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center">
                      <div className="py-6 px-3 mt-32 sm:mt-0">
                        <button className="bg-lightBlue-500 active:bg-lightBlue-600 uppercase text-white font-bold hover:shadow-md shadow text-xs px-4 py-2 rounded outline-none focus:outline-none sm:mr-2 mb-1 ease-linear transition-all duration-150"
                          type="button">Connect</button>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1">
                      <div className="flex justify-center py-4 lg:pt-4 pt-8">
                        <div className="mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">22</span>
                          <span className="text-sm text-blueGray-400">Friends</span>
                        </div>
                        <div className="mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">10</span>
                          <span className="text-sm text-blueGray-400">Photos</span>
                        </div>
                        <div className="lg:mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">89</span>
                          <span className="text-sm text-blueGray-400">Comments</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-blueGray-700">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ يعمل' : '❌ عاطل'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-green-600 font-semibold">
                        📍 يعمل حالياً في: {currentWorkPlace}
                      </p>
                    )}
                    <div className="text-sm leading-normal mt-0 mb-2 text-blueGray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2 text-lg text-blueGray-400"></i> Los Angeles, California
                    </div>
                    <div className="mb-2 text-blueGray-600 mt-10">
                      <i className="fas fa-briefcase mr-2 text-lg text-blueGray-400"></i>
                      {workerInfo.role}
                    </div>
                  </div>
                  
                  {/* المربعان المتجاوران */}
                  <div className="cards-container">
                    {/* مربع CV العامل */}
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-6xl mb-4">📄</div>
                      <h3 className="text-xl font-bold text-white mb-2">Mon CV</h3>
                      <p className="text-gray-300 text-sm">Découvrez mon parcours professionnel, mes compétences et mon expérience</p>
                      <div className="mt-4 text-green-400">Cliquez pour voir →</div>
                    </div>
                    
                    {/* مربع CV المدير */}
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-6xl mb-4">⭐</div>
                      <h3 className="text-xl font-bold text-white mb-2">Évaluations</h3>
                      <p className="text-gray-300 text-sm">Historique des lieux de travail, évaluations et commentaires des managers</p>
                      <div className="mt-4 text-green-400">Cliquez pour voir →</div>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-blueGray-200 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-blueGray-700">
                          {workerInfo.bio}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* Modal CV العامل */}
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            <div style={{ textAlign: 'center' }}>
              <div className="text-6xl mb-4">👩‍💻</div>
              <h2 className="text-2xl font-bold text-white mb-2">{workerInfo.name}</h2>
              <p className="text-green-400 mb-4">{workerInfo.role}</p>
              <div className="text-left">
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📋 À propos</h3>
                <p className="text-gray-300">{workerInfo.bio}</p>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">💪 Compétences</h3>
                <div className="flex flex-wrap gap-2">
                  {workerInfo.skills.map((skill, i) => (
                    <span key={i} className="px-3 py-1 bg-green-500/20 text-green-300 rounded-full text-sm">{skill}</span>
                  ))}
                </div>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📞 Contact</h3>
                <p className="text-gray-300">📧 {workerInfo.email}</p>
                <p className="text-gray-300">📱 {workerInfo.phone}</p>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">🎓 Expérience</h3>
                <p className="text-gray-300">{workerInfo.experience}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal CV المدير (التقييمات) */}
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '700px' }}>
            <button onClick={() => setShowManagerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            <div>
              <div className="text-center">
                <div className="text-6xl mb-4">⭐</div>
                <h2 className="text-2xl font-bold text-white mb-2">Évaluations du Manager</h2>
              </div>
              
              {/* قسم المدير لإضافة تقييم */}
              <div style={{ background: 'rgba(34,197,94,0.1)', borderRadius: '20px', padding: '20px', marginBottom: '20px' }}>
                <h3 className="text-lg font-bold text-green-400 mb-3">👨‍💼 Ajouter une évaluation</h3>
                <div className="mb-3">
                  <label className="text-white text-sm">Lieu de travail actuel: {currentWorkPlace || 'Non défini'}</label>
                </div>
                
                {workerStatus !== 'working' && (
                  <button onClick={activateWorker} className="px-4 py-2 bg-green-500 text-white rounded-lg mb-3">
                    📍 Activer le travailleur
                  </button>
                )}
                
                {workerStatus === 'working' && (
                  <button onClick={deactivateWorker} className="px-4 py-2 bg-red-500 text-white rounded-lg mb-3">
                    🚫 Mettre fin à la période de travail
                  </button>
                )}
                
                {showPlaceSelector && (
                  <div className="place-selector">
                    <h4 className="text-white text-center col-span-full">Choisir un lieu de travail:</h4>
                    {availablePlaces.map(place => (
                      <div key={place.id} className="place-option" onClick={() => changeWorkPlace(place)}>
                        <div className="text-2xl">🏢</div>
                        <div className="text-white font-bold">{place.name}</div>
                        <div className="text-gray-300 text-sm">{place.location}</div>
                      </div>
                    ))}
                  </div>
                )}
                
                <div className="mt-3">
                  <label className="text-white text-sm">⭐ Note (1-5)</label>
                  <div className="rating-input">
                    {[1,2,3,4,5].map(star => (
                      <span key={star} className={`rating-star ${currentRating >= star ? 'active' : ''}`}
                        onClick={() => setCurrentRating(star)}>★</span>
                    ))}
                  </div>
                </div>
                <div className="mt-3">
                  <label className="text-white text-sm">💬 Commentaire</label>
                  <textarea className="w-full p-2 rounded-lg mt-1" rows="3"
                    value={managerComment} onChange={(e) => setManagerComment(e.target.value)}
                    placeholder="Écrivez votre commentaire ici..."></textarea>
                </div>
                <button onClick={addManagerReview} className="mt-3 px-4 py-2 bg-green-500 text-white rounded-lg w-full">
                  ✅ Ajouter l'évaluation
                </button>
              </div>
              
              {/* Liste des évaluations */}
              <h3 className="text-lg font-bold text-white mb-3">📋 Historique des évaluations</h3>
              {workHistory.map((work, index) => (
                <div key={index} className="work-history-item">
                  <div className="flex justify-between items-center flex-wrap">
                    <h4 className="text-white font-bold">{work.place}</h4>
                    <div className="stars">
                      {[...Array(5)].map((_, i) => (
                        <span key={i} style={{ color: i < work.rating ? '#ffc107' : '#4a4a4a', fontSize: '18px' }}>★</span>
                      ))}
                    </div>
                  </div>
                  <p className="text-gray-300 text-sm">{work.role} • {work.duration}</p>
                  <p className="text-gray-400 text-sm mt-2">"{work.review}"</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
